// Base de datos de preguntas RIC
const baseDePreguntas = [
    { pliego: 1, pregunta: "¿Está permitido manipular o retirar los sellos (plomos) instalados por la compañía eléctrica en el equipo de medida para cambiar un cable?", opciones: ["A) Sí, si se es instalador SEC autorizado", "B) Sí, si el dueño de casa lo autoriza", "C) No, alterar o romper los sellos es un delito que se asume como intervención fraudulenta o hurto de energía", "D) Sí, pero solo de día"], respuestaCorrecta: 2, explicacion: "RIC N°01: Los sellos de los medidores son inviolables. Solo el personal directo de la compañía distribuidora puede cortarlos y reponerlos." },
    { pliego: 1, pregunta: "Según el RIC N°01, ¿quién es el único responsable de mantener en buen estado y en condiciones seguras la instalación interior de consumo?", opciones: ["A) La Superintendencia de Electricidad y Combustibles (SEC)", "B) La empresa distribuidora de energía", "C) El instalador eléctrico autorizado", "D) El propietario o usuario de la instalación"], respuestaCorrecta: 3, explicacion: "RIC N°01: El mantenimiento y la seguridad de la instalación interior es de exclusiva responsabilidad del propietario o usuario." },
    { pliego: 1, pregunta: "¿Cuál es la distancia mínima de separación que debe existir entre una caja de empalme eléctrico y un medidor o regulador de gas?", opciones: ["A) 0,20 metros", "B) 0,50 metros", "C) 0,60 metros", "D) 1,00 metro"], respuestaCorrecta: 2, explicacion: "RIC N°01: Se exige una separación mínima de 0,60 m entre cajas de empalme y medidores/reguladores de gas." },
    { pliego: 1, pregunta: "¿Dónde debe ubicarse preferentemente la caja de empalme de una propiedad según el RIC N°01?", opciones: ["A) En el tablero general dentro del domicilio", "B) En la fachada exterior o límite de la propiedad, accesible desde la vía pública", "C) En el poste de la red de distribución", "D) En un lugar oculto para evitar vandalismo"], respuestaCorrecta: 1, explicacion: "RIC N°01: Los empalmes deben ubicarse de tal forma que permitan a la empresa distribuidora la lectura y acceso desde la vía pública." },
    { pliego: 1, pregunta: "¿Qué condición técnica obligatoria debe cumplir el disyuntor general de la instalación interior respecto al empalme?", opciones: ["A) Su capacidad nominal debe ser igual o menor a la capacidad del empalme", "B) Su capacidad nominal debe ser mayor a la del empalme para evitar cortes", "C) Debe ser siempre de 40A o superior", "D) Debe instalarse en la misma caja del medidor"], respuestaCorrecta: 0, explicacion: "RIC N°01: La protección general de la instalación nunca debe superar la capacidad nominal del empalme." },
    { pliego: 1, pregunta: "¿A qué altura debe quedar el visor de lectura (pantalla del medidor) de la caja de empalme respecto del nivel del piso terminado?", opciones: ["A) Entre 0,6 m y 1,0 m", "B) Entre 0,8 m y 2,1 m", "C) Entre 1,5 m y 2,5 m", "D) A 2,5 m mínimo"], respuestaCorrecta: 1, explicacion: "RIC N°01: La ventanilla o visor de lectura del equipo de medida debe quedar a una altura entre 0,8 m y 2,1 m del piso." },
    { pliego: 1, pregunta: "En empalmes aéreos, ¿cuál es la altura mínima libre que debe respetar el conductor de acometida al cruzar calles o caminos públicos?", opciones: ["A) 4,0 metros", "B) 4,5 metros", "C) 5,0 metros", "D) 6,0 metros"], respuestaCorrecta: 2, explicacion: "RIC N°01: En cruces de calles o caminos públicos, la altura mínima del conductor de acometida debe ser de 5,0 metros." },
    { pliego: 1, pregunta: "¿Se permite que los conductores de la acometida aérea pasen por sobre propiedades de terceros?", opciones: ["A) Sí, sin restricciones", "B) Sí, si están a más de 5 metros de altura", "C) No, salvo que exista una servidumbre de paso legalmente constituida", "D) Sí, pero solo si el cable es concéntrico"], respuestaCorrecta: 2, explicacion: "RIC N°01: Prohíbe que la acometida cruce propiedades de terceros a menos que haya una servidumbre legal." },
    { pliego: 1, pregunta: "¿Cuál es la sección mínima del conductor de cobre en una acometida aérea monofásica?", opciones: ["A) 2,5 mm²", "B) 4,0 mm²", "C) 6,0 mm²", "D) 10,0 mm²"], respuestaCorrecta: 1, explicacion: "RIC N°01: Para empalmes monofásicos, la sección mínima de la acometida aérea en cobre es de 4,0 mm²." },
    { pliego: 1, pregunta: "¿Cuál es la sección mínima del conductor de cobre en una acometida aérea trifásica?", opciones: ["A) 4,0 mm²", "B) 6,0 mm²", "C) 10,0 mm²", "D) 16,0 mm²"], respuestaCorrecta: 1, explicacion: "RIC N°01: Para empalmes trifásicos, la sección mínima de la acometida aérea en cobre es de 6,0 mm²." },
    { pliego: 1, pregunta: "En un empalme subterráneo, ¿cuál es la profundidad mínima a la que debe ir enterrado el ducto de la acometida en zonas de tránsito peatonal?", opciones: ["A) 0,40 m", "B) 0,60 m", "C) 0,80 m", "D) 1,00 m"], respuestaCorrecta: 1, explicacion: "RIC N°01: Las canalizaciones subterráneas para empalmes deben tener una profundidad mínima de 0,60 m bajo tierra." },
    { pliego: 1, pregunta: "En un empalme subterráneo que cruza una zona con tránsito vehicular, ¿cuál es la profundidad mínima del ducto?", opciones: ["A) 0,60 m", "B) 0,80 m", "C) 1,00 m", "D) 1,20 m"], respuestaCorrecta: 1, explicacion: "RIC N°01: En zonas con tránsito de vehículos, la profundidad mínima aumenta a 0,80 m." },
    { pliego: 1, pregunta: "¿De qué material deben ser las cajas de empalme metálicas para garantizar su resistencia a la intemperie?", opciones: ["A) Fierro fundido", "B) Aluminio estándar", "C) Plancha de acero galvanizado o con recubrimiento anticorrosivo", "D) Cobre estañado"], respuestaCorrecta: 2, explicacion: "RIC N°01: Las cajas metálicas deben ser de acero con tratamiento anticorrosivo (ej. galvanizado) para resistir la intemperie." },
    { pliego: 1, pregunta: "Si se instala un poste metálico exclusivo para el empalme (tipo bastón), ¿qué exigencia de seguridad es fundamental?", opciones: ["A) Estar pintado de amarillo", "B) Estar conectado a una tierra de protección", "C) Tener una altura mínima de 6 metros", "D) Rellenarse con concreto"], respuestaCorrecta: 1, explicacion: "RIC N°01: Todo poste o estructura metálica utilizada para soportar el empalme debe estar conectada a tierra." },
    { pliego: 1, pregunta: "¿Qué es un empalme provisorio según la normativa?", opciones: ["A) Un empalme usado en viviendas de material ligero", "B) Un empalme destinado a faenas de construcción o eventos por un tiempo definido", "C) Un empalme sin medidor", "D) Un empalme que no requiere declaración SEC"], respuestaCorrecta: 1, explicacion: "RIC N°01: Los empalmes provisorios son transitorios, para instalaciones como faenas o ferias, con un plazo máximo estipulado." },
    { pliego: 1, pregunta: "¿Cuál es el plazo máximo de vigencia que la norma establece por defecto para un empalme provisorio de una obra en construcción?", opciones: ["A) 6 meses, no renovables", "B) El tiempo que dure la obra según el contrato", "C) 1 año, renovable por 6 meses", "D) 3 meses máximo"], respuestaCorrecta: 1, explicacion: "RIC N°01: La vigencia del empalme provisorio está ligada al tiempo justificado para la faena u obra." },
    { pliego: 1, pregunta: "En instalaciones de edificios, ¿dónde se ubican habitualmente los equipos de medida de los empalmes colectivos?", opciones: ["A) En cada departamento", "B) En las escaleras de cada piso", "C) En un recinto o sala de medidores concentrados", "D) En los pasillos comunes de los ascensores"], respuestaCorrecta: 2, explicacion: "RIC N°01: Los empalmes múltiples (edificios) deben agruparse en recintos o armarios exclusivos llamados salas de medidores." },
    { pliego: 1, pregunta: "¿Qué resistencia al fuego mínima (RF) debe tener la puerta de acceso a una sala de medidores en un edificio?", opciones: ["A) RF-30", "B) RF-60", "C) RF-90", "D) RF-120"], respuestaCorrecta: 2, explicacion: "RIC N°01 y RIC N°02 exigen que los recintos que agrupan equipos de medida y protección principal tengan alta resistencia al fuego, típicamente RF-90 o superior." },
    { pliego: 1, pregunta: "¿Está permitido usar la sala de medidores como bodega o cuarto de basura?", opciones: ["A) Sí, si hay espacio suficiente", "B) Sí, si los medidores están en gabinetes cerrados", "C) No, está estrictamente prohibido usarla para otro fin", "D) Solo para guardar artículos de limpieza"], respuestaCorrecta: 2, explicacion: "RIC N°01: Las salas de medidores son de uso exclusivo eléctrico; prohíbe terminantemente almacenar otros elementos." },
    { pliego: 1, pregunta: "En un poste de madera que soporta un empalme, ¿cuál es la profundidad mínima de enterramiento?", opciones: ["A) 1/10 de su longitud total", "B) 1/6 de su longitud total o mínimo 1,2 metros", "C) Mínimo 0,5 metros", "D) Depende exclusivamente del tipo de suelo"], respuestaCorrecta: 1, explicacion: "RIC N°01 (referenciando normativas de redes): El empotramiento estándar de un poste exige un sexto de su longitud (aprox. 1,2m mínimo)." },
    { pliego: 1, pregunta: "¿De quién es la responsabilidad de construir y financiar la cámara de inspección para un empalme subterráneo en la propiedad?", opciones: ["A) Del propietario o cliente", "B) De la compañía eléctrica", "C) Del municipio", "D) De la SEC"], respuestaCorrecta: 0, explicacion: "RIC N°01: Las obras civiles dentro de la propiedad, incluyendo cámaras y ductos, son costo y responsabilidad del cliente." },
    { pliego: 1, pregunta: "En un empalme concentrado (varios medidores), ¿qué elemento es obligatorio antes de cada medidor?", opciones: ["A) Un limitador de sobretensión", "B) Un dispositivo de protección y corte omnipolar (disyuntor)", "C) Un contactor", "D) Un transformador de corriente"], respuestaCorrecta: 1, explicacion: "RIC N°01: Cada medidor en un empalme colectivo debe estar precedido por una protección de corte general (disyuntor)." },
    { pliego: 1, pregunta: "¿Puede instalarse un empalme directamente sobre un cerco vivo (arbustos/plantas)?", opciones: ["A) Sí, si se poda regularmente", "B) Sí, utilizando una caja estanca IP65", "C) No, las cajas de empalme deben montarse en estructuras sólidas e incombustibles", "D) Sí, si el voltaje es monofásico"], respuestaCorrecta: 2, explicacion: "RIC N°01: Se prohíbe la instalación sobre árboles, cercos vivos o estructuras inestables/combustibles." },
    { pliego: 1, pregunta: "¿Qué protección IP mínima debe tener una caja de empalme montada en el exterior (intemperie)?", opciones: ["A) IP20", "B) IP43", "C) IP44 o IP54 según el diseño homologado", "D) IP68"], respuestaCorrecta: 2, explicacion: "RIC N°01/02: Para exterior bajo lluvia directa, se exige al menos IP54 en envolventes eléctricas (o IP44 con aleros protectores, según homologación)." },
    { pliego: 1, pregunta: "¿Es obligatorio instalar una barra o sistema de puesta a tierra en el empalme?", opciones: ["A) No, solo en el tablero de distribución", "B) Sí, la tierra de servicio debe estar conectada en el empalme o en la caja más cercana", "C) Solo si es un empalme trifásico", "D) Solo en edificios"], respuestaCorrecta: 1, explicacion: "RIC N°01/05: El neutro de la compañía debe aterrizarse (Tierra de Servicio) en el empalme o lo más cerca posible del punto de entrega." },
    { pliego: 1, pregunta: "¿Cuál es la función del sello de plomo o plástico que instala la compañía eléctrica en el empalme?", opciones: ["A) Proteger contra la humedad", "B) Evitar que los insectos entren al medidor", "C) Evitar y evidenciar la intervención no autorizada (hurto de energía)", "D) Mejorar la conductividad eléctrica"], respuestaCorrecta: 2, explicacion: "RIC N°01: Los sellos aseguran la integridad de la medida y previenen el fraude." },
    { pliego: 1, pregunta: "Si el empalme se instala en una pared colindante con una vía pública muy estrecha sin vereda, ¿dónde debe ir el medidor?", opciones: ["A) En el mismo muro exterior sobresaliendo", "B) Embutido en el muro para no obstaculizar el paso", "C) En un poste a 3 metros de altura", "D) Dentro de la casa"], respuestaCorrecta: 1, explicacion: "RIC N°01: En zonas sin acera, para evitar golpes o estorbar, la caja debe ir embutida." },
    { pliego: 1, pregunta: "Para empalmes de más de 10 kW, ¿qué consideración de medida puede aplicar la distribuidora?", opciones: ["A) Medición indirecta con transformadores de corriente (TC)", "B) Eliminar el disyuntor", "C) Usar solo medidores analógicos", "D) Cobrar tarifa plana"], respuestaCorrecta: 0, explicacion: "RIC N°01: Para cargas altas, la corriente supera la capacidad del medidor directo, obligando al uso de Transformadores de Corriente (TC)." },
    { pliego: 1, pregunta: "¿Qué color debe tener el conductor de Neutro en la acometida desde la red al empalme?", opciones: ["A) Negro", "B) Blanco", "C) Desnudo (siempre)", "D) Verde"], respuestaCorrecta: 1, explicacion: "RIC N°04 (aplicable al RIC 01 en conexiones interiores): El neutro se identifica con color blanco." },
    { pliego: 1, pregunta: "La canalización de entrada (tubo) al empalme desde una red subterránea debe tener una pendiente. ¿Con qué propósito?", opciones: ["A) Para que los cables entren más rápido", "B) Para evitar la acumulación y el ingreso de agua hacia la caja del empalme", "C) Para mejorar la ventilación", "D) Para reducir el campo magnético"], respuestaCorrecta: 1, explicacion: "RIC N°01: Se debe evitar que la condensación o el agua de lluvia escurra hacia el medidor." },
    { pliego: 1, pregunta: "¿Qué es el 'Punto de entrega' en un empalme?", opciones: ["A) El último enchufe de la casa", "B) Los bornes de salida del medidor o disyuntor general del empalme", "C) El poste de la esquina", "D) El transformador de la ciudad"], respuestaCorrecta: 1, explicacion: "RIC N°01: El punto de entrega marca la frontera entre la red de distribución y la instalación interior del cliente." },
    { pliego: 2, pregunta: "Un tablero general con una capacidad instalada de 100 Amperes o superior está obligado a contener en su interior o en la puerta:", opciones: ["A) Un diagrama unilineal impreso o termolaminado de sus circuitos", "B) Un listado con el teléfono del instalador", "C) Un interruptor horario", "D) Espacio para guardar herramientas"], respuestaCorrecta: 0, explicacion: "RIC N°02: Para tableros grandes (>100A), tener a la vista el diagrama unilineal físico es obligatorio para actuar rápido en emergencias." },
    { pliego: 2, pregunta: "¿Es admisible que tuberías de agua, desagües o redes de gas pasen a través del interior o justo por encima de un armario que alberga tableros eléctricos principales?", opciones: ["A) Sí, si están pintadas de otro color", "B) No, las canalizaciones de otras disciplinas están estrictamente prohibidas en el recinto y volumen exclusivo del tablero eléctrico", "C) Sí, solo las de agua fría", "D) Sí, pero con doble tubo"], respuestaCorrecta: 1, explicacion: "RIC N°02: El espacio eléctrico es sagrado. No se permiten cruces de fluidos por el riesgo gravísimo de goteras, roturas o explosiones." },
    { pliego: 2, pregunta: "¿Cuál es el volumen libre (reserva) mínimo que debe tener un tablero para futuras ampliaciones?", opciones: ["A) 10%", "B) 15%", "C) 25%", "D) 40%"], respuestaCorrecta: 2, explicacion: "RIC N°02 exige un mínimo de 25% de espacio o capacidad libre para futuras modificaciones o agregados." },
    { pliego: 2, pregunta: "¿A qué altura debe quedar el punto de operación (palancas de disyuntores) más alto en un tablero eléctrico?", opciones: ["A) Máximo 1,5 metros", "B) Máximo 2,0 metros", "C) Máximo 2,5 metros", "D) Sin límite"], respuestaCorrecta: 1, explicacion: "RIC N°02: La altura de operación de los dispositivos no debe exceder los 2,0 metros respecto del piso." },
    { pliego: 2, pregunta: "¿A qué altura debe quedar el punto de operación más bajo en un tablero eléctrico?", opciones: ["A) Mínimo 0,2 metros", "B) Mínimo 0,45 metros", "C) Mínimo 1,0 metro", "D) A nivel del piso"], respuestaCorrecta: 1, explicacion: "RIC N°02: Los dispositivos más bajos deben estar a una altura mínima de 0,45 metros del piso." },
    { pliego: 2, pregunta: "En tableros instalados al exterior (intemperie), ¿cuál es el grado de protección IP mínimo exigido?", opciones: ["A) IP20", "B) IP41", "C) IP44", "D) IP54"], respuestaCorrecta: 3, explicacion: "RIC N°02 exige que los tableros a la intemperie tengan un grado de protección no inferior a IP54." },
    { pliego: 2, pregunta: "En lugares de ambiente húmedo, ¿qué grado de protección debe tener el tablero eléctrico?", opciones: ["A) IP20", "B) IP41", "C) IP44", "D) IP54"], respuestaCorrecta: 2, explicacion: "RIC N°02: Para recintos húmedos o mojados bajo techo, la norma pide un mínimo de IP44." },
    { pliego: 2, pregunta: "¿Qué es un tablero de distribución (TD)?", opciones: ["A) El que recibe la alimentación directa del empalme y protege toda la instalación", "B) El que recibe alimentación de un tablero general y protege un grupo específico de circuitos finales", "C) El tablero de la compañía eléctrica", "D) Una caja de derivación grande"], respuestaCorrecta: 1, explicacion: "RIC N°02 define al Tablero de Distribución como el derivado del Tablero General que agrupa circuitos finales." },
    { pliego: 2, pregunta: "Todo tablero con más de tres circuitos de salida debe contar obligatoriamente con:", opciones: ["A) Un disyuntor general", "B) Un voltímetro", "C) Puerta con cerradura de seguridad", "D) Pintura epóxica roja"], respuestaCorrecta: 0, explicacion: "RIC N°02: Tableros con más de 3 derivaciones (circuitos) requieren una protección general de corte omnipolar." },
    { pliego: 2, pregunta: "¿Qué es el 'mandil' o 'placa muerta' de un tablero?", opciones: ["A) La puerta exterior de la caja", "B) Una cubierta interior que oculta las barras y cables, dejando solo a la vista las manillas de operación", "C) La placa de datos técnicos", "D) La barra de tierra de cobre"], respuestaCorrecta: 1, explicacion: "RIC N°02: El mandil evita que el usuario toque partes energizadas al accionar los disyuntores." },
    { pliego: 2, pregunta: "El espesor mínimo de la plancha de acero para construir un tablero metálico hasta 100A es de:", opciones: ["A) 0,5 mm", "B) 1,0 mm", "C) 1,5 mm", "D) 2,0 mm"], respuestaCorrecta: 1, explicacion: "RIC N°02: Para tableros residenciales comunes metálicos, se exige un espesor mínimo de plancha de 1,0 mm o 1,5 mm dependiendo de las dimensiones." },
    { pliego: 2, pregunta: "¿De qué material deben ser las barras de distribución (buses) dentro de un tablero de alta capacidad?", opciones: ["A) Aluminio sin recubrimiento", "B) Acero inoxidable", "C) Cobre electrolítico de alta pureza", "D) Bronce"], respuestaCorrecta: 2, explicacion: "RIC N°02: Las barras colectoras y de distribución deben ser de cobre electrolítico de 99,9% de pureza o aluminio estañado bajo ciertas normas." },
    { pliego: 2, pregunta: "¿Se permite el uso de maderas o aglomerados para la construcción de la envolvente (caja) de un tablero eléctrico?", opciones: ["A) Sí, si están pintadas", "B) Sí, para tableros domiciliarios monofásicos", "C) No, están estrictamente prohibidas por ser material combustible", "D) Sí, pero solo la puerta"], respuestaCorrecta: 2, explicacion: "RIC N°02 prohíbe materiales inflamables e higroscópicos como la madera para envolventes de tableros." },
    { pliego: 2, pregunta: "¿Qué orden de colores deben tener las barras de un tablero trifásico (Fase 1, Fase 2, Fase 3)?", opciones: ["A) Azul, Negro, Rojo", "B) Rojo, Azul, Negro", "C) Blanco, Negro, Rojo", "D) Azul, Blanco, Verde"], respuestaCorrecta: 0, explicacion: "RIC N°02 y 04: El código de colores es Fase 1 Azul, Fase 2 Negro y Fase 3 Rojo." },
    { pliego: 2, pregunta: "¿Se permite instalar un tablero general en el interior de un cuarto de baño o ducha?", opciones: ["A) Sí, si tiene grado IP65", "B) Sí, a más de 2 metros de la tina", "C) No, está prohibido instalar tableros en salas de baño", "D) Sí, pero solo si es de material plástico"], respuestaCorrecta: 2, explicacion: "RIC N°02 / RIC N°11: Prohíbe expresamente la instalación de tableros de distribución en recintos de baño." },
    { pliego: 2, pregunta: "¿Es obligatorio incluir un directorio o leyenda indicando los circuitos dentro del tablero?", opciones: ["A) Solo en industrias", "B) No es necesario", "C) Sí, todo tablero debe tener una rotulación clara y permanente del destino de cada circuito", "D) Solo para los diferenciales"], respuestaCorrecta: 2, explicacion: "RIC N°02: La rotulación que identifique qué protege cada disyuntor es una exigencia de seguridad obligatoria." },
    { pliego: 2, pregunta: "Si en un tablero entran conductores con aislamiento libre de halógenos (para lugares de reunión de personas), ¿cómo debe ser la canaleta ranurada interna del tablero?", opciones: ["A) Estándar de PVC azul", "B) De aluminio reforzado", "C) También de material libre de halógenos", "D) No se permite usar canaletas"], respuestaCorrecta: 2, explicacion: "RIC N°02 y 07: En zonas de reunión, todos los elementos plásticos (cables, canaletas, amarras) deben ser libres de halógenos." },
    { pliego: 2, pregunta: "¿Cuál es el espacio libre de trabajo mínimo que debe existir frente a un tablero eléctrico para su mantenimiento?", opciones: ["A) 0,5 metros", "B) 0,8 metros", "C) 1,0 metro", "D) 1,5 metros"], respuestaCorrecta: 2, explicacion: "RIC N°02 exige un espacio de trabajo libre, seguro y despejado de al menos 1,0 m frente al tablero." },
    { pliego: 2, pregunta: "¿Pueden cruzarse los conductores de las Fases con los de las corrientes débiles (TV, Internet) dentro del mismo tablero eléctrico de fuerza?", opciones: ["A) Sí, si están amarrados juntos", "B) No, deben estar en compartimientos o tableros físicamente separados", "C) Sí, si el tablero es grande", "D) Sí, pero con cinta aislante doble"], respuestaCorrecta: 1, explicacion: "RIC N°02: Las corrientes débiles deben ir en tableros y canalizaciones exclusivas, separadas de los circuitos de fuerza y alumbrado." },
    { pliego: 2, pregunta: "Para evitar contactos indirectos, la envolvente metálica (caja) de un tablero debe estar siempre conectada a:", opciones: ["A) La barra de neutro", "B) La tierra de servicio", "C) La barra de tierra de protección", "D) El pararrayos"], respuestaCorrecta: 2, explicacion: "RIC N°02 / 05: Todo elemento conductor accesible que no forma parte del circuito (masas) debe conectarse a la Tierra de Protección." },
    { pliego: 2, pregunta: "¿Qué significa que un tablero esté fabricado bajo norma y certificado (Sello SEC)?", opciones: ["A) Que es más barato", "B) Que fue probado en laboratorios contra cortocircuitos, resistencia al calor, impactos e IP", "C) Que solo sirve para 380V", "D) Que no necesita diferenciales"], respuestaCorrecta: 1, explicacion: "RIC N°02 exige que los materiales y ensambles cuenten con certificación de seguridad para garantizar su correcto desempeño ante fallas." },
    { pliego: 2, pregunta: "Las luces piloto indicadoras de tensión en la puerta de un tablero deben protegerse mediante:", opciones: ["A) Disyuntores de 10A a 16A", "B) Fusibles o disyuntores de bajo amperaje (ej: 2A a 6A)", "C) No llevan protección", "D) Un diferencial exclusivo"], respuestaCorrecta: 1, explicacion: "RIC N°02: Los circuitos de medición y luces piloto deben derivarse desde barras principales usando protecciones calibradas para esa carga minúscula." },
    { pliego: 2, pregunta: "Si el tablero cuenta con una puerta exterior sólida, los dispositivos operables (disyuntores) deben ser accesibles:", opciones: ["A) Solo con herramienta especial", "B) Al abrir dicha puerta sin necesidad de herramientas", "C) Retirando tornillos", "D) Rompiendo un vidrio"], respuestaCorrecta: 1, explicacion: "RIC N°02: La operación de reseteo o corte de los automáticos debe ser posible por cualquier usuario abriendo la puerta principal sin herramientas." },
    { pliego: 2, pregunta: "En tableros con capacidad sobre 100A, ¿es obligatorio instalar luces piloto?", opciones: ["A) No", "B) Sí, una por cada fase para indicar la presencia de tensión", "C) Sí, pero solo de color rojo", "D) Solo en tableros de motores"], respuestaCorrecta: 1, explicacion: "RIC N°02: Tableros de alta capacidad requieren señalización visual (pilotos) para evidenciar qué líneas están energizadas." },
    { pliego: 3, pregunta: "Si se instalan varios cables alimentadores agrupados fuertemente en una misma bandeja portacables, su capacidad de transportar corriente disminuye. A esto se le aplica un:", opciones: ["A) Factor de agrupamiento (reducción de amperaje admisible por temperatura)", "B) Aumento de voltaje", "C) Factor de potencia", "D) Aislante extra"], respuestaCorrecta: 0, explicacion: "RIC N°03: Muchos cables juntos no disipan bien el calor. La norma obliga a aplicar factores de corrección que reducen la corriente que el cable puede llevar." },
    { pliego: 3, pregunta: "¿Qué conductor no debe reducirse de sección en un subalimentador trifásico si se anticipa alta presencia de armónicos (cargas electrónicas no lineales como computadores o LED masivos)?", opciones: ["A) La fase 1", "B) El conductor de Neutro (debe mantenerse igual o superior a las fases)", "C) La Tierra", "D) El conductor piloto"], respuestaCorrecta: 1, explicacion: "RIC N°03: Las cargas electrónicas inyectan armónicos al neutro, lo que puede hacer que por el neutro pase más corriente que por las fases, provocando su incendio si es muy delgado." },
    { pliego: 3, pregunta: "Según el RIC N°03, ¿cómo se define un 'Alimentador'?", opciones: ["A) Conductor que va desde el medidor hasta el primer tablero", "B) Conductor entre un enchufe y un aparato", "C) El cable que trae la energía desde la subestación de la ciudad", "D) Cualquier cable dentro de una tubería"], respuestaCorrecta: 0, explicacion: "RIC N°03: Alimentador es el conductor que conecta el empalme (punto de entrega) con el Tablero General de la instalación." },
    { pliego: 3, pregunta: "¿Qué es un 'Subalimentador' según el RIC N°03?", opciones: ["A) Un cable de repuesto", "B) El conductor que alimenta tableros de distribución derivados desde un tablero general u otro de distribución", "C) El cable de tierra", "D) Un cable de menor grosor que la fase"], respuestaCorrecta: 1, explicacion: "RIC N°03: Es el tramo de conductores que distribuye energía entre tableros al interior de la propiedad." },
    { pliego: 3, pregunta: "La sección (grosor) mínima de los conductores empleados como Alimentadores no podrá ser inferior a:", opciones: ["A) 1,5 mm²", "B) 2,5 mm²", "C) 4,0 mm²", "D) 6,0 mm²"], respuestaCorrecta: 2, explicacion: "RIC N°03: Establece como 4,0 mm² la sección mínima admisible para conductores de Alimentadores (y 2,5 mm² para Subalimentadores en algunos casos menores, pero la regla general base de alimentador arranca en 4mm²)." },
    { pliego: 3, pregunta: "La caída de tensión en un Alimentador (desde el medidor hasta el tablero general) no debe superar el:", opciones: ["A) 1%", "B) 3%", "C) 5%", "D) 10%"], respuestaCorrecta: 1, explicacion: "RIC N°03: El límite máximo permitido de caída de voltaje en un alimentador es del 3%." },
    { pliego: 3, pregunta: "La caída de tensión total (Alimentador + Subalimentador + Circuito Final) no puede exceder el:", opciones: ["A) 3%", "B) 5%", "C) 7%", "D) 10%"], respuestaCorrecta: 1, explicacion: "RIC N°03: Sumando todos los tramos hasta el punto de consumo más lejano, la caída total máxima es 5%." },
    { pliego: 3, pregunta: "Si se instalan Alimentadores a la intemperie de forma aérea (colgantes), la sección mínima del conductor será:", opciones: ["A) 2,5 mm²", "B) 4,0 mm²", "C) 6,0 mm² (si el vano supera los 15 metros)", "D) 10,0 mm²"], respuestaCorrecta: 2, explicacion: "RIC N°03 y normativas de tracción mecánica exigen secciones más gruesas (como 6 mm²) para cables aéreos soportando su propio peso en vanos largos." },
    { pliego: 3, pregunta: "En sistemas trifásicos, si la sección de la Fase es de 35 mm², ¿cómo debe ser la sección del Neutro de ese alimentador?", opciones: ["A) Siempre igual a la fase (35 mm²)", "B) La mitad (aprox 16 mm²)", "C) 4 mm²", "D) No requiere neutro"], respuestaCorrecta: 1, explicacion: "RIC N°03: Para fases mayores a 16mm² de cobre, el neutro puede reducirse a la mitad de la fase (con un mínimo de 16mm²), previo cálculo de armónicos." },
    { pliego: 3, pregunta: "Los conductores de un Alimentador que cruzan paredes, techos o entretechos combustibles deben ir:", opciones: ["A) Al aire libre para que respiren", "B) En canalizaciones cerradas e incombustibles (tuberías, bandejas con tapa)", "C) Amarrados con alambre a las vigas", "D) Cubiertos con yeso"], respuestaCorrecta: 1, explicacion: "RIC N°03: Los alimentadores en zonas ocultas o combustibles deben estar canalizados protegiendo contra riesgo de incendio y daño mecánico." },
    { pliego: 4, pregunta: "La sigla THHN en un conductor eléctrico nos indica que su aislamiento principal es:", opciones: ["A) De goma resistente al agua", "B) Termoplástico de alta resistencia al calor con una chaqueta exterior de nylon transparente", "C) Libre de halógenos", "D) De teflón"], respuestaCorrecta: 1, explicacion: "RIC N°04: T (Thermoplastic), HH (High Heat resistant, 90°C), N (Nylon jacket). Es el cable más común para canalizaciones en tubos." },
    { pliego: 4, pregunta: "¿Qué tipo de cables están diseñados y permitidos para ser directamente enterrados en el suelo (zanjas) sin necesidad de una tubería de protección?", opciones: ["A) Cables monopolares THHN", "B) Cables armados, concéntricos o con cubierta exterior extrudida especialmente diseñada para enterramiento directo (ej. RV-K, Superflex enterrable)", "C) Cable paralelo de lámpara", "D) Cualquier cable si se le pone huincha"], respuestaCorrecta: 1, explicacion: "RIC N°04: Enterrar cables desnudos o de tubo (THHN) los pudre en meses. Se requieren cables tipo taller pesados con chaquetas probadas para tierra y humedad." },
    { pliego: 4, pregunta: "Si se canalizan tuberías eléctricas cerca de tuberías de calefacción o agua caliente, la distancia mínima de separación entre ellas debe ser:", opciones: ["A) 0,05 metros", "B) 0,15 metros (y cruzarse preferentemente de forma perpendicular)", "C) 1,0 metro", "D) Pueden ir amarradas juntas"], respuestaCorrecta: 1, explicacion: "RIC N°04: El calor degrada la aislación eléctrica. Se exige alejar las cañerías calientes a un mínimo de 15 cm de los ductos eléctricos." },
    { pliego: 4, pregunta: "¿Qué colores establece el RIC N°04 para identificar las Fases 1, 2 y 3 respectivamente en un sistema trifásico?", opciones: ["A) Azul, Negro y Rojo", "B) Rojo, Blanco y Azul", "C) Negro, Blanco y Rojo", "D) Azul, Verde y Rojo"], respuestaCorrecta: 0, explicacion: "RIC N°04: El código de colores obligatorio es Fase 1: Azul, Fase 2: Negro, Fase 3: Rojo." },
    { pliego: 4, pregunta: "¿Qué material de conductor está prohibido para instalaciones interiores de baja tensión de viviendas y locales comerciales estándar?", opciones: ["A) Cobre", "B) Aluminio (en secciones menores a 16 mm²)", "C) Cobre estañado", "D) Aleación de cobre"], respuestaCorrecta: 1, explicacion: "RIC N°04 prohíbe el uso de conductores de aluminio en instalaciones interiores en Baja Tensión, salvo casos muy específicos industriales o en secciones muy grandes (sobre 16 mm²) con equipos especiales." },
    { pliego: 4, pregunta: "¿Cuál es la sección mínima permitida para los conductores de un circuito exclusivo de alumbrado?", opciones: ["A) 1,0 mm²", "B) 1,5 mm²", "C) 2,5 mm²", "D) 4,0 mm²"], respuestaCorrecta: 1, explicacion: "RIC N°04 exige un mínimo de 1,5 mm² para circuitos de iluminación." },
    { pliego: 4, pregunta: "¿Cuántas curvas de 90° se permiten como máximo en una canalización de tubería (tubo rígido) entre dos cajas contiguas sin tener que instalar una caja de paso?", opciones: ["A) 1 curva (90°)", "B) 2 curvas (180°)", "C) 3 curvas (270°)", "D) 4 curvas (360°)"], respuestaCorrecta: 2, explicacion: "RIC N°04: Entre dos cajas contiguas, el recorrido no puede tener más de tres curvas de 90° (270° en total)." },
    { pliego: 4, pregunta: "Si en una tubería instalas 1 solo conductor, ¿cuál es el porcentaje máximo de área (factor de relleno) que este puede ocupar?", opciones: ["A) 31%", "B) 40%", "C) 53%", "D) 60%"], respuestaCorrecta: 2, explicacion: "RIC N°04: Para 1 conductor el máximo es 53%, para 2 es 31% y para 3 o más es 40%." },
    { pliego: 4, pregunta: "Si en una tubería instalas 2 conductores, ¿cuál es el porcentaje máximo de área (factor de relleno) permitido?", opciones: ["A) 25%", "B) 31%", "C) 40%", "D) 53%"], respuestaCorrecta: 1, explicacion: "RIC N°04: Al usar exactamente 2 conductores, el factor de ocupación permitido se reduce al 31% para evitar atascamientos." },
    { pliego: 4, pregunta: "¿Qué restricción impone la norma al uso de tuberías metálicas flexibles (corrugadas metálicas) en las instalaciones?", opciones: ["A) No se pueden usar en longitudes mayores a 1,5 metros y deben quedar a la vista", "B) Solo se pueden usar bajo tierra", "C) Se deben usar para todo el circuito de enchufes", "D) Están totalmente prohibidas"], respuestaCorrecta: 0, explicacion: "RIC N°04: Las tuberías flexibles metálicas se usan solo en tramos cortos (máx 1,5m) para conectar equipos vibratorios (motores) y deben estar visibles." },
    { pliego: 4, pregunta: "¿Es legal realizar una unión (empalme) de conductores en el tramo interior de una tubería EMT?", opciones: ["A) Sí, si se aíslan con cinta 3M", "B) Sí, pero solo soldando los cables", "C) No, todas las uniones deben realizarse obligatoriamente dentro de cajas de derivación o conexión", "D) Sí, si la tubería es mayor a 32 mm"], respuestaCorrecta: 2, explicacion: "RIC N°04 prohíbe terminantemente dejar empalmes o uniones dentro de los ductos." },
    { pliego: 4, pregunta: "Las cajas de derivación instaladas en techos falsos o entretechos deben:", opciones: ["A) Quedar cubiertas por el aislante térmico", "B) Ser siempre metálicas y soldadas", "C) Quedar siempre accesibles y con sus tapas instaladas", "D) Estar pintadas de rojo"], respuestaCorrecta: 2, explicacion: "RIC N°04: Toda caja de derivación debe contar con su tapa respectiva y quedar accesible para futuras inspecciones o mantenimientos." },
    { pliego: 4, pregunta: "En una canalización a la vista con tubería rígida no metálica (PVC), ¿cuál es la distancia máxima permitida entre dos abrazaderas o fijaciones sucesivas?", opciones: ["A) 0,5 metros", "B) 1,2 metros", "C) 2,0 metros", "D) 3,0 metros"], respuestaCorrecta: 1, explicacion: "RIC N°04: Para tubos plásticos rígidos (PVC), la separación máxima entre soportes/fijaciones no debe superar 1,20 m." },
    { pliego: 4, pregunta: "Al realizar una canalización subterránea en jardines o zonas sin tránsito de vehículos, ¿a qué profundidad mínima deben enterrarse los ductos eléctricos?", opciones: ["A) 0,20 m", "B) 0,40 m", "C) 0,60 m", "D) 1,00 m"], respuestaCorrecta: 2, explicacion: "RIC N°04: La profundidad general mínima es 0,60 m (puede bajar a 0,40 m si se cubre con loseta de hormigón de 5 cm)." },
    { pliego: 4, pregunta: "¿Qué requisito deben cumplir las bandejas portacables (escalerillas) respecto a los tableros que alimentan?", opciones: ["A) Deben estar conectadas equipotencialmente a la tierra de protección", "B) Deben ser de plástico obligatoriamente", "C) Deben pintarse del color de la pared", "D) Deben tener doble aislamiento"], respuestaCorrecta: 0, explicacion: "RIC N°04/05: Toda canalización metálica a la vista, como escalerillas o bandejas, es una masa y debe conectarse a la Tierra de Protección." },
    { pliego: 4, pregunta: "Cuando cables de corrientes débiles (Internet, TV, citofonía) van en paralelo con cables de fuerza (220V/380V), ¿cómo deben canalizarse?", opciones: ["A) Todos en el mismo tubo plástico", "B) En canalizaciones separadas (distintos ductos) con tabiques separadores si comparten bandeja", "C) Juntos si los de fuerza son libres de halógenos", "D) Trenzados entre sí para anular ruido"], respuestaCorrecta: 1, explicacion: "RIC N°04: Las corrientes débiles no pueden compartir ducto ni caja con fuerza por riesgo eléctrico y de interferencia electromagnética." },
    { pliego: 4, pregunta: "Si se utilizan molduras plásticas (canaletas) sobrepuestas en los muros de una casa, ¿qué prohíbe la norma?", opciones: ["A) Llevar conductores de alumbrado", "B) Su uso a menos de 1 metro del techo", "C) Atravesar muros o losas embutiendo la moldura", "D) Usar accesorios curvos"], respuestaCorrecta: 2, explicacion: "RIC N°04: Las molduras ranuradas son exclusivas para montaje a la vista; no pueden atravesar paredes estando embutidas, para eso se usa tubería." },
    { pliego: 5, pregunta: "¿A qué se le denomina 'Voltaje de Paso' en un sistema de puestas a tierra?", opciones: ["A) A la caída de tensión en el medidor", "B) A la diferencia de voltaje que recibe una persona entre sus dos pies (separados aprox. 1 metro) cuando camina sobre un terreno donde se está descargando una falla eléctrica", "C) Al voltaje que pasa por el diferencial", "D) A la corriente estática de la alfombra"], respuestaCorrecta: 1, explicacion: "RIC N°05: Al descargar una falla a tierra, el terreno se electrifica en círculos concéntricos. Dar un paso largo puede matarte porque un pie recibe un voltaje mayor que el otro." },
    { pliego: 5, pregunta: "Para evitar la corrosión galvánica (que un metal se coma a otro) en las conexiones bajo tierra de las puestas a tierra, se debe:", opciones: ["A) Mezclar hierro, cobre y zinc libremente", "B) Evitar el contacto directo bajo tierra de metales disímiles o utilizar soldadura exotérmica (cadweld)", "C) Usar solo abrazaderas de fierro oxidado", "D) Pintar la varilla con antióxido"], respuestaCorrecta: 1, explicacion: "RIC N°05: Unir cobre con fierro directamente en la tierra mojada crea una pila que destruye la conexión. Se exige soldadura por fusión (exotérmica) o conectores bimetálicos." },
    { pliego: 5, pregunta: "¿Qué es la Tierra de Protección?", opciones: ["A) Conexión a tierra del Neutro de la compañía", "B) Conexión de las carcasas metálicas (masas) de los equipos eléctricos al suelo para evitar tensiones de contacto peligrosas", "C) Una barra para derivar pararrayos", "D) El cable rojo del enchufe"], respuestaCorrecta: 1, explicacion: "RIC N°05: La tierra de protección une las masas de la instalación a tierra, asegurando que las personas no sufran descargas por fallas de aislamiento." },
    { pliego: 5, pregunta: "¿Qué es la Tierra de Servicio?", opciones: ["A) La tierra para conectar computadores", "B) La tierra conectada a las carcasas de lavadoras", "C) La conexión a tierra del punto neutro de la alimentación (transformador o empalme)", "D) Una barra superficial"], respuestaCorrecta: 2, explicacion: "RIC N°05: Fija el voltaje de referencia del sistema, conectando a tierra el Neutro en la subestación y en el empalme." },
    { pliego: 5, pregunta: "En lugares secos, ¿qué voltaje se considera 'Tensión de Seguridad', bajo el cual no hay riesgo letal para personas adultas?", opciones: ["A) 12 V", "B) 24 V", "C) 50 V", "D) 110 V"], respuestaCorrecta: 2, explicacion: "RIC N°05: En ambiente seco, se establece un máximo de 50V de corriente alterna." },
    { pliego: 5, pregunta: "En lugares húmedos o mojados (ej. piscinas), ¿qué voltaje se considera 'Tensión de Seguridad'?", opciones: ["A) 12 V", "B) 24 V", "C) 50 V", "D) 220 V"], respuestaCorrecta: 1, explicacion: "RIC N°05: Debido a que la resistencia del cuerpo baja al estar mojado, la tensión de seguridad máxima se reduce a 24V." },
    { pliego: 5, pregunta: "¿Se pueden utilizar las tuberías metálicas de agua potable o gas como electrodos (barras) de puesta a tierra?", opciones: ["A) Sí, porque están enterradas", "B) Sí, si el gásfiter lo aprueba", "C) No, está estrictamente prohibido utilizar tuberías de agua, gas u otros fluidos como electrodos de tierra", "D) Sí, pero solo para tierra de protección"], respuestaCorrecta: 2, explicacion: "RIC N°05 prohíbe terminantemente usar redes metálicas de fluidos como sistema de tierra por riesgo de explosión y corrosión." },
    { pliego: 5, pregunta: "¿Qué color debe tener el aislamiento del conductor de Puesta a Tierra de Protección (PE)?", opciones: ["A) Blanco o Gris", "B) Negro o Rojo", "C) Exclusivamente Verde o Verde con franjas Amarillas", "D) Azul claro"], respuestaCorrecta: 2, explicacion: "RIC N°05 (y N°04) reserva el color verde o bicolor verde/amarillo mundialmente para la tierra de protección." },
    { pliego: 5, pregunta: "En un empalme (Sistema TN-C-S), donde se unen la Tierra de Servicio y la Tierra de Protección, el esquema se conoce como:", opciones: ["A) Aislado (IT)", "B) Neutralización", "C) Doble Tierra", "D) Sistema Flotante"], respuestaCorrecta: 1, explicacion: "RIC N°05: El esquema donde el neutro se une a la tierra de protección en el origen se llama esquema de neutralización (TN)." },
    { pliego: 5, pregunta: "¿Qué accesorio físico es obligatorio para poder inspeccionar un electrodo de puesta a tierra (ej: barra Cooperweld) instalado en el jardín?", opciones: ["A) Una tapa de madera", "B) Una cámara de registro inspeccionable a ras de suelo", "C) Un tubo de PVC cerrado", "D) Nada, se entierra tapado con tierra compacta"], respuestaCorrecta: 1, explicacion: "RIC N°05: La cabecera del electrodo y su conector deben quedar accesibles mediante una cámara de registro para medición y mantenimiento." },
    { pliego: 5, pregunta: "El conductor que une el tablero eléctrico con el electrodo enterrado (Cable de Puesta a Tierra), debe tener una sección mínima de:", opciones: ["A) 1,5 mm²", "B) 2,5 mm²", "C) 4,0 mm²", "D) 10,0 mm²"], respuestaCorrecta: 2, explicacion: "RIC N°05: El conductor del electrodo a tierra (para empalmes normales) exige una sección no menor a 4,0 mm²." },
    { pliego: 5, pregunta: "¿De qué forma debe conectarse el conductor de tierra de protección a la carcasa metálica de un equipo o a la barra de un tablero?", opciones: ["A) Enrollándolo en un tornillo con la mano", "B) Soldándolo con estaño tradicional", "C) Mediante terminales de compresión (ojales) o conectores certificados", "D) Pegándolo con cinta aislante"], respuestaCorrecta: 2, explicacion: "RIC N°05: Para garantizar que el cable soporte la energía de un cortocircuito a masa sin soltarse, se prohíbe el uso de estaño y se exigen terminales o prensas de buena conductividad." },
    { pliego: 6, pregunta: "¿Qué pasa si se instala un interruptor diferencial de 300 mA (en vez de 30 mA) en el circuito general de enchufes de una casa?", opciones: ["A) Es mejor porque salta menos", "B) Es un peligro mortal, 300 mA no protegen la vida humana (causan fibrilación ventricular); se usan solo para protección contra riesgo de incendios en industrias", "C) Es la norma actual para casas", "D) Reduce el consumo"], respuestaCorrecta: 1, explicacion: "RIC N°06: La corriente que mata o paraliza el corazón ronda los 30mA - 50mA. Un diferencial de 300mA dejará que una persona se electrocute sin dispararse." },
    { pliego: 6, pregunta: "¿Cuáles son las dos funciones principales de un disyuntor termomagnético (Automático)?", opciones: ["A) Proteger contra sobrecargas y evitar que te dé la corriente", "B) Proteger contra cortocircuitos y medir la energía", "C) Proteger a los conductores contra sobrecargas y cortocircuitos", "D) Regular el voltaje y reducir la boleta de luz"], respuestaCorrecta: 2, explicacion: "RIC N°06: Los termomagnéticos protegen la instalación (cables) contra corrientes lentas excesivas (sobrecarga) y contactos bruscos de fases (cortocircuito)." },
    { pliego: 6, pregunta: "¿Cuál es la función exclusiva de un Interruptor Diferencial (RCD)?", opciones: ["A) Proteger la vida de las personas, mascotas y bienes contra fugas de corriente a tierra (contactos indirectos)", "B) Cortar la luz si hay un cortocircuito", "C) Evitar que se quemen los electrodomésticos por alza de voltaje", "D) Reducir el parpadeo de luces"], respuestaCorrecta: 0, explicacion: "RIC N°06: El RCD monitorea corrientes residuales (fugas); si detecta que la corriente 'sale' del sistema hacia la tierra (ej. a través de una persona), corta el circuito." },
    { pliego: 6, pregunta: "¿Qué significa que un disyuntor sea de 'Curva C'?", opciones: ["A) Que es para circuitos de iluminación LED", "B) Que su protección magnética actúa entre 5 y 10 veces su corriente nominal, ideal para circuitos de uso general domiciliario", "C) Que soporta grandes motores", "D) Que su protección es solo térmica"], respuestaCorrecta: 1, explicacion: "RIC N°06: La Curva C es la estándar para aplicaciones de alumbrado y enchufes generales." },
    { pliego: 6, pregunta: "Si conectas un motor que al encender consume muchísima corriente de partida, ¿qué curva de disyuntor es la correcta para que no salte inmediatamente?", opciones: ["A) Curva A", "B) Curva B", "C) Curva C", "D) Curva D"], respuestaCorrecta: 3, explicacion: "RIC N°06: La Curva D aguanta picos altísimos de arranque (10 a 20 veces la corriente nominal) sin saltar, especial para máquinas." },
    { pliego: 6, pregunta: "Para instalaciones en viviendas residenciales, ¿cuál debe ser la capacidad de ruptura (poder de corte) mínima de los disyuntores?", opciones: ["A) 3 kA (3.000 A)", "B) 4,5 kA (4.500 A)", "C) 6 kA (6.000 A)", "D) 10 kA (10.000 A)"], respuestaCorrecta: 2, explicacion: "RIC N°06: Se unificó el estándar chileno: la ruptura mínima en protección residencial es de 6 kA (kiloamperes)." },
    { pliego: 6, pregunta: "¿En qué conductor NO DEBE instalarse NUNCA un dispositivo de protección unipolar (ej: un fusible o automático simple)?", opciones: ["A) En la Fase 1", "B) En el Neutro", "C) En la Fase 3", "D) En ningún lado"], respuestaCorrecta: 1, explicacion: "RIC N°06: Cortar solo el Neutro dejaría todo el circuito energizado (vivo) con un peligro latente. El Neutro no se corta solo, a menos que sea un corte omnipolar (fase+neutro a la vez)." },
    { pliego: 6, pregunta: "¿Qué significa 'Selectividad' o coordinación de protecciones?", opciones: ["A) Que todos los automáticos deben ser iguales", "B) Que si hay una falla en un enchufe, salte el automático de ese circuito y no el general, aislando la falla", "C) Que el cliente pueda seleccionar el color del automático", "D) Que el medidor corte la energía primero"], respuestaCorrecta: 1, explicacion: "RIC N°06 exige que los sistemas se diseñen de forma selectiva: la protección más cercana a la falla es la única que debe operar." },
    { pliego: 6, pregunta: "Para circuitos que alimentan equipos de computación o cargadores de autos eléctricos, el diferencial exigido es de Tipo:", opciones: ["A) Tipo AC", "B) Tipo A o Tipo B (detectan fugas en corriente continua o pulsante)", "C) Solo Curva D", "D) Termomagnético"], respuestaCorrecta: 1, explicacion: "RIC N°06: La electrónica moderna distorsiona la fuga. El Tipo AC clásico queda ciego; se exige Tipo A o B." },
    { pliego: 6, pregunta: "Según la norma, ¿dónde se instala el dispositivo de protección contra sobretensiones transitorias (DPS o supresor de picos)?", opciones: ["A) En el poste de luz", "B) En los tableros generales, aguas arriba o en paralelo a la carga para descargar los rayos o alzas a tierra", "C) En el techo de la casa", "D) Solo en el enchufe del televisor"], respuestaCorrecta: 1, explicacion: "RIC N°06: Los DPS se colocan en los tableros y desvían los picos transitorios violentos directamente al sistema de tierra de protección." },
    { pliego: 6, pregunta: "¿Es correcto utilizar un disyuntor termomagnético en un tablero como interruptor de encendido y apagado diario de una luminaria?", opciones: ["A) Sí, si es de marca certificada", "B) Sí, ahorra comprar interruptores", "C) No, los disyuntores no están diseñados para maniobras frecuentes de uso de carga", "D) Sí, pero solo de 10A"], respuestaCorrecta: 2, explicacion: "RIC N°06: Prohíbe utilizar las protecciones termomagnéticas como elementos de comando habitual (para eso son los contactores o interruptores de palanca)." },
    { pliego: 7, pregunta: "¿A partir de qué capacidad (carga de ocupación) un recinto cerrado se considera 'Lugar de Reunión de Personas'?", opciones: ["A) 25 personas", "B) 50 personas", "C) 100 personas", "D) 200 personas"], respuestaCorrecta: 2, explicacion: "RIC N°07: Edificios o locales con capacidad para reunir a más de 100 personas se rigen por normativas más estrictas de seguridad." },
    { pliego: 7, pregunta: "¿Qué exigencia principal aplica a los cables y canalizaciones plásticas usados en lugares de reunión de personas (ej: teatros, colegios, supermercados)?", opciones: ["A) Deben ser de color naranja fluorescente", "B) Deben ser blindados en plomo", "C) Deben ser 'Libres de halógenos, baja emisión de humos y baja toxicidad' (LZSH/LS0H)", "D) Deben ser de aluminio"], respuestaCorrecta: 2, explicacion: "RIC N°07: En caso de incendio, los cables normales emiten ácido y humo negro letal. En locales masivos, se exige cable RZ1-K o similar libre de halógenos." },
    { pliego: 7, pregunta: "En un lugar de reunión de personas, los equipos de emergencia (alarmas de incendio, bombas de agua) deben canalizarse de forma especial. ¿Cuál?", opciones: ["A) Sus ductos deben ir pintados de verde", "B) Sus conductores y canalizaciones deben tener resistencia probada al fuego para operar durante un incendio", "C) Deben conectarse con enchufes de pared normales", "D) No requieren canalización"], respuestaCorrecta: 1, explicacion: "RIC N°07 y 08 exigen conductores resistentes al fuego (RF) que aseguren la operatividad de los sistemas críticos mientras la gente evacúa." },
    { pliego: 8, pregunta: "Los letreros de señalización 'SALIDA' luminosos autónomos deben mantenerse encendidos:", opciones: ["A) Solo de noche", "B) Todo el tiempo, y contar con batería para seguir operando por al menos 90 minutos ante cortes de luz", "C) Solo si hay un incendio", "D) Máximo por 10 minutos"], respuestaCorrecta: 1, explicacion: "RIC N°08: Las señales de escape deben ser permanentemente visibles y tener autonomía probada de hora y media para grandes evacuaciones." },
    { pliego: 8, pregunta: "¿Qué nivel de iluminación mínimo (en Lux) debe proveer el sistema de emergencia en una ruta de evacuación a nivel de piso?", opciones: ["A) 0,1 Lux", "B) 1 Lux", "C) 10 Lux", "D) 50 Lux"], respuestaCorrecta: 1, explicacion: "RIC N°08: La luz de escape debe garantizar al menos 1 lux en el eje central de la ruta de evacuación al nivel del suelo." },
    { pliego: 8, pregunta: "Si el edificio cuenta con un Grupo Electrógeno (generador) para cargas críticas, este debe arrancar y asumir la carga en un tiempo no mayor a:", opciones: ["A) 5 segundos", "B) 15 segundos", "C) 60 segundos", "D) 5 minutos"], respuestaCorrecta: 1, explicacion: "RIC N°08: Los sistemas de respaldo críticos (clase 15) deben transferir la carga en 15 segundos máximo desde el corte." },
    { pliego: 9, pregunta: "En un sistema fotovoltaico (paneles solares), ¿qué equipo cumple la función de convertir la Corriente Continua (DC) generada por los paneles a Corriente Alterna (AC) para el uso de la casa?", opciones: ["A) El regulador de carga", "B) El inversor", "C) El transformador de aislación", "D) El tablero de transferencia"], respuestaCorrecta: 1, explicacion: "RIC N°09: El Inversor es el corazón del sistema, transformando la energía continua de los paneles en energía alterna compatible con la red y los electrodomésticos." },
    { pliego: 9, pregunta: "¿Qué es la protección 'Anti-Isla' (o Anti-Islanding) obligatoria en los inversores conectados a la red (Net Billing)?", opciones: ["A) Evita que el panel se moje si está aislado", "B) Un sistema que apaga el inversor si detecta que la red pública cortó la luz, para no inyectar energía y electrocutar a los linieros que estén reparando la calle", "C) Un aislante de temperatura para baterías", "D) Evitar que funcionen en islas geográficas"], respuestaCorrecta: 1, explicacion: "RIC N°09: La protección anti-isla es vital por seguridad humana. Si la SEC corta la energía en la calle, tu inversor debe apagarse automáticamente." },
    { pliego: 9, pregunta: "¿Qué tipo de conductores deben usarse en el lado de corriente continua (DC) de los paneles solares que están expuestos a la intemperie y al sol?", opciones: ["A) Cable THHN estándar de colores", "B) Cables libres de halógenos", "C) Cables solares específicos con aislamiento resistente a rayos UV y condiciones climáticas extremas", "D) Cables paralelos (cordón) encintados"], respuestaCorrecta: 2, explicacion: "RIC N°09: Los cables del lado DC sufren un estrés térmico y de radiación brutal. Se exigen conductores fotovoltaicos (ej. PV1-F) certificados para intemperie y UV." },
    { pliego: 9, pregunta: "Las estructuras metálicas de aluminio o acero que soportan los paneles solares en el techo de una casa deben:", opciones: ["A) Quedar aisladas y no conectarse a nada", "B) Conectarse obligatoriamente al sistema de Tierra de Protección de la instalación mediante conductores equipotenciales", "C) Pintarse con pintura aislante de alto voltaje", "D) Conectarse a la fase principal"], respuestaCorrecta: 1, explicacion: "RIC N°09: Toda masa metálica asociada a los paneles debe aterrizarse para evitar tensiones de contacto en caso de falla de un cable contra la estructura." },
    { pliego: 9, pregunta: "¿Se permite canalizar los cables de corriente continua (DC) de los paneles en la misma tubería por donde pasan los cables de corriente alterna (AC) de la casa?", opciones: ["A) Sí, si la tubería es de un diámetro mayor a 32mm", "B) Sí, no hay restricción", "C) No, los circuitos de DC y AC deben canalizarse en forma independiente y en tuberías separadas", "D) Sí, pero con cables de colores distintos"], respuestaCorrecta: 2, explicacion: "RIC N°09: Para evitar errores de maniobra, arcos y por diferencias de clase de voltaje, AC y DC no pueden compartir la misma tubería o compartimento." },
    { pliego: 10, pregunta: "¿Qué función cumple un enchufe GFCI o diferencial integrado (los que traen botones TEST y RESET en la misma placa)?", opciones: ["A) Mide el consumo eléctrico del secador de pelo", "B) Cumple la misma función de protección contra fugas a tierra que un diferencial de tablero, pero aplicado localmente en zonas de alto riesgo (baños, mesones de cocina)", "C) Es un enchufe para enchufes europeos", "D) Protege solo contra sobrecargas térmicas"], respuestaCorrecta: 1, explicacion: "RIC N°10/11: Son ideales para recintos húmedos. Si cae agua al aparato, el enchufe GFCI corta la luz instantáneamente sin tener que ir al tablero." },
    { pliego: 10, pregunta: "Un interruptor simple de luz que comanda una ampolleta de forma segura debe cortar la continuidad física de:", opciones: ["A) El Neutro (cable blanco)", "B) La Fase (cable de color)", "C) La Tierra (cable verde)", "D) Los tres al mismo tiempo"], respuestaCorrecta: 1, explicacion: "RIC N°10: La regla de oro del alumbrado. El interruptor corta la Fase. Así, cuando apagas la luz, no hay voltaje en la base metálica ni en el soquete, permitiendo el cambio seguro de la bombilla." },
    { pliego: 10, pregunta: "Para instalar un tomacorriente en un balcón, terraza o jardín a la intemperie total, ¿qué exigencia se debe cumplir?", opciones: ["A) Instalar un enchufe normal y pedirle al cliente que no lo moje", "B) Instalarlo dentro de una caja con grado de protección IP54 o superior, con tapa que mantenga el sellado incluso estando conectado", "C) Colocarle una bolsa de plástico", "D) Los enchufes al exterior están prohibidos"], respuestaCorrecta: 1, explicacion: "RIC N°10: Para exteriores sin techo, el enchufe debe ser estanco (con tapa de cierre hermético) para soportar lluvia y polvo sin cortocircuitarse." },
    { pliego: 10, pregunta: "En un pasillo largo o una escalera, el sistema ideal normado para apagar y prender la misma luz desde dos puntos distintos es:", opciones: ["A) Un interruptor simple y desenchufar la ampolleta", "B) Un interruptor diferencial", "C) Un circuito con interruptores de combinación (9/24)", "D) Dos interruptores simples en paralelo"], respuestaCorrecta: 2, explicacion: "RIC N°10: La conexión 9/24 permite la conmutación segura del alumbrado desde múltiples posiciones (inicio y fin de la escalera)." },
    { pliego: 10, pregunta: "¿Puede un mismo circuito final o automático alimentar a la vez enchufes e iluminación?", opciones: ["A) Sí, sin restricciones", "B) Sí, pero no se recomienda. Si se hace, el circuito entero requerirá protección diferencial", "C) No, los circuitos de alumbrado y fuerza deben ser siempre 100% separados (salvo ampliaciones menores muy justificadas)", "D) Sí, pero solo usando cables de 4mm²"], respuestaCorrecta: 2, explicacion: "RIC N°10 impone la separación de cargas. Alumbrado y enchufes deben ir en automáticos distintos y ductos distintos." },
    { pliego: 10, pregunta: "¿Cuál es la potencia mínima a considerar por cada módulo de enchufe al diseñar y calcular la capacidad del tablero general residencial?", opciones: ["A) 100 W", "B) 150 VA", "C) 250 W por caja", "D) 500 W"], respuestaCorrecta: 2, explicacion: "RIC N°10: Tradicionalmente (y por la NCH 4/2003 actualizada en RIC), para cálculo de carga, cada salida (caja) de enchufe simple o múltiple residencial se estima en 250 W." },
    { pliego: 10, pregunta: "Si una lavadora o secadora tiene una potencia conocida de 2.000 W, ¿qué se exige para su instalación?", opciones: ["A) Un enchufe normal de 10A", "B) Cortar su enchufe y unir los cables a la pared", "C) Que pertenezca a un circuito de uso general", "D) Un circuito independiente exclusivo con su propio automático y cables dimensionados a su carga", ], respuestaCorrecta: 3, explicacion: "RIC N°10: Todo electrodoméstico o máquina cuya potencia sea igual o superior a 2.000 W debe contar con circuito independiente." },
    { pliego: 10, pregunta: "¿Cuál es la altura reglamentaria de montaje para interruptores de luz (comandos) medida desde el piso terminado?", opciones: ["A) Entre 0,80 m y 1,40 m", "B) A 1,50 m exactos", "C) Entre 1,20 m y 1,80 m", "D) Arriba de 2 metros"], respuestaCorrecta: 0, explicacion: "RIC N°10: Los interruptores deben montarse en un rango de 0,80 a 1,40 metros (para facilitar también accesibilidad universal)." },
    { pliego: 10, pregunta: "¿Cuál es la altura mínima recomendada y normativa para instalar enchufes de uso general en los muros?", opciones: ["A) A ras de piso", "B) A no menos de 0,15 m (o 0,20 m en algunos recintos) del nivel del piso terminado", "C) A 1,00 m", "D) Mínimo a 1,50 m para evitar que niños los toquen"], respuestaCorrecta: 1, explicacion: "RIC N°10: La altura mínima es 0,15m - 0,20m para evitar ingresos de agua por limpieza y facilitar conexiones." },
    { pliego: 10, pregunta: "En cocinas, los enchufes sobre el mesón de trabajo deben estar instalados al menos a una distancia vertical del mesón de:", opciones: ["A) 5 cm", "B) 10 a 15 cm", "C) 50 cm", "D) 1 metro"], respuestaCorrecta: 1, explicacion: "RIC N°10: Los enchufes de mesón no pueden ir rasantes por riesgo de derrames, deben ir elevados entre 10 y 15 cm del borde superior." },
    { pliego: 10, pregunta: "¿Cuántos conductores puede conectar como máximo bajo el mismo borne (tornillo) de un interruptor o enchufe estándar?", opciones: ["A) 1 solo conductor. Si hay derivación debe hacerse con cola de ratón (unión) fuera del enchufe", "B) 2 conductores", "C) Hasta 3 si entran", "D) No hay norma al respecto"], respuestaCorrecta: 0, explicacion: "RIC N°10 (y N°04): Se prohíbe usar los bornes de los aparatos como regleta de derivación para puentear a otros enchufes. Se exige hacer la unión atrás (caja) y sacar un solo cable (chicote) al borne." },
    { pliego: 10, pregunta: "¿Es obligatorio el uso de enchufes con alveolos protegidos (obturadores tipo 'child-protection') en las viviendas chilenas?", opciones: ["A) Solo en salas cunas", "B) No, son opcionales", "C) Sí, todos los tomacorrientes (enchufes) instalados en zonas residenciales y asimilables deben contar con sistema de protección infantil en sus contactos", "D) Solo los que estén a menos de 1 metro"], respuestaCorrecta: 2, explicacion: "RIC N°10: Para evitar accidentes por inserción de elementos, todos los enchufes nuevos deben tener protección contra contactos accidentales." },
    { pliego: 10, pregunta: "El automático que protege circuitos de alumbrado, ¿qué curva de disparo magnético debe tener?", opciones: ["A) Curva B o C", "B) Curva D", "C) Curva K", "D) Curva Z"], respuestaCorrecta: 0, explicacion: "RIC N°06/10: Las cargas de iluminación (luces LED, incandescentes, etc) operan perfectamente con protecciones Curva B o C (uso general domiciliario)." },
    { pliego: 10, pregunta: "¿Está permitido usar cables paralelos gemelos (cordones tipo cable de lámpara) para cableado fijo dentro de paredes o techos?", opciones: ["A) Sí, si es un circuito de menos de 10A", "B) Sí, porque son más fáciles de pasar", "C) No, los cordones flexibles están estrictamente prohibidos para canalizaciones fijas de la propiedad", "D) Sí, pero solo si van en tuberías metálicas"], respuestaCorrecta: 2, explicacion: "RIC N°04 y 10: El cable flexible tipo cordón se limita a electrodomésticos portátiles y lámparas colgantes, nunca como parte del circuito empotrado de la casa." },
    { pliego: 11, pregunta: "¿Qué tipo de canalización eléctrica está permitida dentro del Volumen 0 (el interior del agua) de una piscina?", opciones: ["A) Tuberías de PVC a la vista", "B) Canalizaciones metálicas herméticas", "C) Ninguna, excepto las exclusivas para alimentar los equipos permitidos en ese mismo volumen", "D) Bandejas portacables plásticas"], respuestaCorrecta: 2, explicacion: "RIC N°11: Por riesgo de electrocución, se prohíbe pasar cables por dentro del agua salvo los estrictamente necesarios para alimentar focos o bombas sumergibles." },
    { pliego: 11, pregunta: "En los recintos alrededor de una piscina (borde húmedo o Volumen 1), ¿cuál es el grado de protección mínimo contra agua que deben tener los equipos eléctricos?", opciones: ["A) IPX4", "B) IPX5", "C) IPX7", "D) IPX8"], respuestaCorrecta: 1, explicacion: "RIC N°11: En el Volumen 1 de piscinas, los equipos deben estar protegidos contra chorros de agua, es decir, mínimo IPX5." },
    { pliego: 11, pregunta: "¿A qué distancia mínima del borde interior de una piscina (inicio del Volumen 2) se permite instalar un enchufe o interruptor de 220V?", opciones: ["A) A 0,6 metros", "B) A 1,2 metros", "C) A 2,0 metros", "D) A 3,0 metros"], respuestaCorrecta: 2, explicacion: "RIC N°11: Los enchufes e interruptores están prohibidos en el Volumen 0 y 1. Recién se permiten en el Volumen 2, a una distancia de 2,0 metros del borde." },
    { pliego: 11, pregunta: "En las cabinas de Sauna, ¿está permitido instalar interruptores o enchufes de uso general en el interior de la cabina?", opciones: ["A) Sí, si tienen tapa estanca IP65", "B) Sí, pero a ras de piso", "C) No, está estrictamente prohibido instalar dispositivos de maniobra y tomacorrientes en su interior", "D) Sí, pero solo de 12V"], respuestaCorrecta: 2, explicacion: "RIC N°11: Las altas temperaturas y humedad constante en un sauna hacen peligrosísimo cualquier punto de contacto eléctrico, por lo que se prohíben dentro de la cabina." },
    { pliego: 11, pregunta: "En cuartos de baño y duchas, todas las partes conductoras expuestas (tuberías de agua metálicas, marcos) deben estar conectadas a:", opciones: ["A) La cañería del gas", "B) Una unión equipotencial suplementaria conectada a la tierra de protección", "C) La fase del circuito de iluminación", "D) El Neutro del enchufe"], respuestaCorrecta: 1, explicacion: "RIC N°11 exige que todas las masas y elementos metálicos en baños se conecten entre sí y a tierra (equipotencialidad) para que no haya diferencia de voltaje si alguien los toca." },
    { pliego: 12, pregunta: "El término 'Zona Clasificada Ex' en la normativa se refiere a:", opciones: ["A) Lugares excluidos de fiscalización", "B) Locales extra-grandes", "C) Áreas con presencia de gases, vapores inflamables o polvos combustibles donde una chispa eléctrica causaría una explosión inminente", "D) Oficinas de gerencia"], respuestaCorrecta: 2, explicacion: "RIC N°12: Las zonas clasificadas (gasolineras, molinos harineros, plantas químicas) requieren canalizaciones herméticas y a prueba de chispas." },
    { pliego: 12, pregunta: "En instalaciones con riesgo de explosión, ¿qué función cumple el 'sello cortafuego' en las canalizaciones de tuberías?", opciones: ["A) Filtrar la humedad del aire", "B) Evitar el paso de gases inflamables o llamas desde una zona a otra a través del ducto", "C) Aumentar la conductividad del cable", "D) Sostener mecánicamente los conductores pesados"], respuestaCorrecta: 1, explicacion: "RIC N°12: Los sellos se rellenan con masilla especial para bloquear la tubería e impedir que una explosión o gas viaje por dentro del tubo hacia otros recintos." },
    { pliego: 12, pregunta: "¿Qué tipo de equipos eléctricos se permiten en una 'Zona 0' (lugar donde la atmósfera explosiva de gas está presente de forma continua o por largos periodos)?", opciones: ["A) Cualquier equipo en caja plástica", "B) Solo equipos con modo de protección 'Seguridad Intrínseca' (Ex ia) diseñados para no generar la energía suficiente para encender el gas", "C) Motores estándar de inducción", "D) Tableros de distribución abiertos"], respuestaCorrecta: 1, explicacion: "RIC N°12: La Zona 0 es la más peligrosa. Solo se admiten aparatos de seguridad intrínseca que operan con corrientes y voltajes microscópicos incapaces de generar una chispa." },
    { pliego: 12, pregunta: "En áreas clasificadas con riesgo de explosión, toda canalización metálica debe garantizar continuidad eléctrica y estar conectada obligatoriamente a:", opciones: ["A) La tierra de protección para evitar descargas por chispas de electricidad estática", "B) La cañería de combustible", "C) El neutro general del empalme", "D) No deben conectarse a nada"], respuestaCorrecta: 0, explicacion: "RIC N°12: La acumulación de estática puede generar una micro chispa y volar el recinto; por eso la equipotencialidad (puesta a tierra) de todo lo metálico es vital." },
    { pliego: 12, pregunta: "¿Está permitido realizar empalmes (uniones) de conductores eléctricos en el interior de tuberías o cajas estándar dentro de áreas clasificadas (Ex)?", opciones: ["A) Sí, usando soldadura y huincha de goma", "B) No, los empalmes están prohibidos dentro de ductos y solo pueden hacerse en cajas o accesorios certificados a prueba de explosión (Ex)", "C) Sí, si se hacen con regletas plásticas", "D) Sí, pero solo en Media Tensión"], respuestaCorrecta: 1, explicacion: "RIC N°12: Cualquier unión es un punto potencial de chispa. Solo pueden hacerse en cajas especiales Ex que confinan y soportan explosiones internas." },
    { pliego: 13, pregunta: "En hospitales, algunos enchufes son de un color específico (generalmente ROJO) para indicar que:", opciones: ["A) Son de alto voltaje", "B) Son exclusivos para limpieza", "C) Están respaldados por la red de energía de emergencia (Grupo Electrógeno o UPS) y garantizan continuidad para equipos médicos", "D) Están dañados"], respuestaCorrecta: 2, explicacion: "RIC N°13: El código visual (rojo) alerta a médicos y personal que ese enchufe nunca perderá energía vital en caso de apagón." },
    { pliego: 13, pregunta: "En un recinto médico, ¿cuál es el objetivo del esquema de conexión a tierra IT Médico?", opciones: ["A) Reducir la cuenta de luz", "B) Aislar eléctricamente el circuito respecto a tierra para que la energía NO SE CORTE si ocurre una primera falla de aislación", "C) Apagar inmediatamente todos los equipos ante cualquier falla", "D) Reemplazar el uso de los protectores diferenciales"], respuestaCorrecta: 1, explicacion: "RIC N°13: En un pabellón o UCI no puedes permitir que salte el automático por un cable pelado. El sistema IT aísla el circuito de tierra para mantener los equipos de soporte vital funcionando." },
    { pliego: 13, pregunta: "En salas de operaciones (Pabellones), ¿en qué tiempo máximo debe entrar a funcionar el suministro de energía de emergencia si falla la red normal de la ciudad?", opciones: ["A) 0,5 segundos (Clase 0.5)", "B) 5 segundos", "C) 15 segundos", "D) 60 segundos"], respuestaCorrecta: 0, explicacion: "RIC N°13: Para los sistemas críticos de soporte vital en el Grupo 2 (pabellones), la energía debe volver en menos de medio segundo (generalmente apoyado por UPS)." },
    { pliego: 13, pregunta: "¿Qué dispositivo de vigilancia debe acompañar de forma obligatoria al transformador de aislación en un esquema IT médico?", opciones: ["A) Un diferencial de 300 mA", "B) Un monitor de aislamiento (DVI) que avise visual y acústicamente cuando ocurra una falla", "C) Un contactor tripolar", "D) Un medidor de consumo de red"], respuestaCorrecta: 1, explicacion: "RIC N°13: Como la primera falla no corta la luz, el monitor de aislamiento alerta a los médicos para que el equipo de mantenimiento repare el problema luego de la cirugía." },
    { pliego: 13, pregunta: "¿Qué dispositivo de protección se omite deliberadamente aguas abajo del transformador de aislación en un quirófano para evitar que se apague el soporte vital?", opciones: ["A) El disyuntor termomagnético general", "B) La protección diferencial (RCD) contra contactos indirectos", "C) Los fusibles de comando", "D) El supresor de transientes"], respuestaCorrecta: 1, explicacion: "RIC N°13: Instalar un diferencial normal en el secundario de un transformador IT médico provocaría que los equipos de vida se apaguen, matando al paciente." },
    { pliego: 13, pregunta: "Para evitar micro descargas al corazón de los pacientes, la red de equipotencialidad en salas quirúrgicas exige que la resistencia entre cualquier punto metálico y la barra de tierra no supere los:", opciones: ["A) 0,2 ohms", "B) 1,0 ohm", "C) 5,0 ohms", "D) 20,0 ohms"], respuestaCorrecta: 0, explicacion: "RIC N°13: Exige un nivel de equipotencialidad altísimo. La resistencia de las conexiones de protección no puede superar los 0,2 ohms." },
    { pliego: 14, pregunta: "En recintos agrícolas donde se utilice agua a presión (mangueras) para la limpieza de galpones, el grado de protección mínimo de los equipos eléctricos será:", opciones: ["A) IP20", "B) IP44", "C) IP55", "D) IP68"], respuestaCorrecta: 2, explicacion: "RIC N°14: Si hay proyecciones de agua por aseo (chorros), la protección mínima requerida sube a IP55." },
    { pliego: 14, pregunta: "Debido a que los animales son más susceptibles al voltaje que los humanos, ¿qué sensibilidad máxima obligatoria deben tener los diferenciales que protegen enchufes en locales agrícolas?", opciones: ["A) 10 mA", "B) 30 mA", "C) 100 mA", "D) 300 mA"], respuestaCorrecta: 1, explicacion: "RIC N°14: Se exige protección diferencial con sensibilidad máxima de 30 mA para salvaguardar al ganado y al personal." },
    { pliego: 14, pregunta: "En galpones de concentración de animales, ¿dónde recomienda la norma ubicar las canalizaciones eléctricas para prevenir daños mecánicos?", opciones: ["A) Embutidas en el piso de concreto", "B) Por fuera del recinto o en posiciones fuera del alcance físico de los animales", "C) Al nivel de los comederos", "D) Colgando libremente de los techos"], respuestaCorrecta: 1, explicacion: "RIC N°14 exige tomar precauciones contra impactos mecánicos e interacción con los animales, instalando los cables preferentemente en altura." },
    { pliego: 14, pregunta: "En recintos destinados al almacenamiento de paja, heno o forraje, ¿qué tipo de luminarias están prohibidas por su alto riesgo de provocar incendios?", opciones: ["A) Luminarias LED", "B) Luminarias herméticas IP65", "C) Luminarias sin pantalla o cubierta protectora que dejen expuesta la ampolleta o fuente de calor", "D) Luminarias fluorescentes"], respuestaCorrecta: 2, explicacion: "RIC N°14 prohíbe las fuentes de luz desprotegidas en zonas de polvo o forraje inflamable, exigiendo envolventes que aíslen el calor y eviten la acumulación de material." },
    { pliego: 14, pregunta: "¿Está permitido el uso de conductores de Aluminio en las instalaciones interiores de ambientes agrícolas o ganaderos?", opciones: ["A) Sí, para abaratar costos", "B) No, solo se permite el uso de conductores de Cobre en las instalaciones interiores", "C) Sí, pero solo en la fase", "D) Sí, si las distancias superan los 100 metros"], respuestaCorrecta: 1, explicacion: "RIC N°14 (y el RIC N°04 en general) prohíbe el uso del aluminio en redes interiores residenciales/agrícolas estándar por problemas de oxidación y dilatación térmica." },
    { pliego: 15, pregunta: "En la infraestructura de recarga de vehículos eléctricos (SAVE), ¿es necesario usar un circuito especial desde el tablero?", opciones: ["A) No, se puede conectar a un enchufe de cocina o lavadero que esté desocupado", "B) Sí, todo punto de carga debe estar alimentado por un circuito exclusivo y dedicado para ese fin", "C) Solo es necesario si la carga es superior a 10 kW", "D) Solo en electrolineras públicas"], respuestaCorrecta: 1, explicacion: "RIC N°15: La recarga somete al circuito a corrientes máximas por horas. Se exige circuito independiente desde el tablero para evitar recalentamientos." },
    { pliego: 15, pregunta: "¿Qué tipo de protección diferencial es obligatoria para proteger un circuito de recarga de vehículo eléctrico en corriente alterna (si el cargador no la trae integrada)?", opciones: ["A) Tipo AC tradicional", "B) Tipo A o Tipo B (que sean capaces de detectar fugas de componentes de corriente continua)", "C) Un fusible rápido", "D) Un disyuntor Curva C"], respuestaCorrecta: 1, explicacion: "RIC N°15: Las baterías y cargadores pueden inyectar fugas de corriente continua (DC) hacia la red de la casa. Se exige diferencial Tipo A con detector DC 6mA o derechamente un Tipo B." },
    { pliego: 15, pregunta: "Si se instala un tablero eléctrico exclusivo para alimentar cargadores de vehículos en el exterior (a la intemperie), ¿cuál es su grado IP mínimo?", opciones: ["A) IP41", "B) IP44", "C) IP54", "D) IP67"], respuestaCorrecta: 2, explicacion: "RIC N°15 y RIC N°02 exigen que todo equipo de distribución eléctrica expuesto al clima exterior cumpla con protección IP54 o superior." },
    { pliego: 15, pregunta: "¿Cuál es la sección (grosor) mínima que exige la norma para los conductores de cobre en un circuito destinado a recargar un vehículo eléctrico?", opciones: ["A) 1,5 mm²", "B) 2,5 mm²", "C) 4,0 mm²", "D) 6,0 mm²"], respuestaCorrecta: 1, explicacion: "RIC N°15: Define como sección mínima absoluta 2,5 mm², aunque dependiendo de la potencia del cargador, habitualmente se requiere calcular grosores mayores." },
    { pliego: 15, pregunta: "¿Se permite instalar permanentemente un cargador usando un tomacorriente (enchufe) doméstico estándar (tipo chuco o italiano)?", opciones: ["A) Sí, si la casa tiene diferencial", "B) Sí, con un adaptador de buena calidad", "C) No, deben utilizarse conectores y bases industriales o específicos homologados para carga de vehículos eléctricos", "D) Sí, pero solo si es de color azul"], respuestaCorrecta: 2, explicacion: "RIC N°15: Los enchufes domésticos se derriten ante el uso continuo a máxima potencia. Se exigen tomas de uso industrial (ej. IEC 60309) o dedicadas a electromovilidad." },
    { pliego: 16, pregunta: "¿Qué es un 'Subsistema de Distribución'?", opciones: ["A) La red de media tensión de la ciudad", "B) Un tablero derivado pequeño", "C) Las redes e instalaciones eléctricas emplazadas en el interior de un predio o condominio privado que distribuyen energía a diferentes usuarios", "D) Un transformador en un poste público"], respuestaCorrecta: 2, explicacion: "RIC N°16: Aplica a condominios de casas, edificios o loteos industriales, donde la red interna pertenece y es mantenida por los copropietarios." },
    { pliego: 16, pregunta: "En un condominio con un subsistema de distribución, ¿quién es el responsable del mantenimiento de las redes y postes de luz interiores?", opciones: ["A) La Municipalidad", "B) La empresa eléctrica (ej: Enel, CGE)", "C) La comunidad de copropietarios o el administrador del condominio", "D) El instalador que construyó la red original"], respuestaCorrecta: 2, explicacion: "RIC N°16: Al ser una red privada 'aguas abajo' del empalme general, el mantenimiento es costo y responsabilidad de la comunidad." },
    { pliego: 16, pregunta: "Para las canalizaciones subterráneas de un condominio, ¿cuál es la profundidad mínima exigida bajo las calles interiores donde circulan vehículos?", opciones: ["A) 0,40 metros", "B) 0,60 metros", "C) 0,80 metros", "D) 1,20 metros"], respuestaCorrecta: 2, explicacion: "RIC N°16 (y RIC 04): En cruces vehiculares, las zanjas y ductos deben tener al menos 0,80 metros de profundidad." },
    { pliego: 17, pregunta: "Para instalaciones de consumo de gran tamaño (potencia instalada superior a 100 kW), el propietario debe contar de forma obligatoria con:", opciones: ["A) Un técnico eléctrico de guardia las 24 horas", "B) Un manual y un programa de operación y mantenimiento escrito, actualizado y disponible", "C) Dos empalmes redundantes", "D) Un generador a petróleo"], respuestaCorrecta: 1, explicacion: "RIC N°17: Las grandes instalaciones están obligadas a tener protocolos formales de mantenimiento preventivo y manuales de operación documentados." },
    { pliego: 17, pregunta: "Previo a intervenir un tablero eléctrico energizado para mantenimiento, la regla primordial de seguridad ocupacional (las 5 Reglas de Oro) indica que se debe:", opciones: ["A) Ponerse guantes y trabajar rápido", "B) Bajar el automático principal y avisar a gritos", "C) Cortar efectivamente la energía, bloquear/etiquetar el dispositivo de corte y verificar la ausencia de tensión con un instrumento adecuado", "D) Trabajar solo de día"], respuestaCorrecta: 2, explicacion: "RIC N°17: El bloqueo (Lockout/Tagout) y la verificación instrumental de ausencia de tensión son innegociables para salvar vidas de los técnicos." },
    { pliego: 17, pregunta: "¿Qué son los planos 'As-Built' exigidos por la normativa de mantenimiento?", opciones: ["A) Los planos originales que hizo el arquitecto", "B) Los planos de estructura del edificio", "C) Los planos que reflejan exactamente cómo quedó construida la instalación eléctrica en la realidad, incluyendo cualquier modificación posterior", "D) Planos en 3D del tablero"], respuestaCorrecta: 2, explicacion: "RIC N°17: Mantener los planos 'As-Built' (como fue construido) actualizados es responsabilidad del propietario y crucial para futuros mantenimientos o resolución de fallas." },
    { pliego: 17, pregunta: "El uso de Elementos de Protección Personal (EPP) dieléctricos (guantes aislantes, casco sin partes metálicas, zapatos sin puntera de acero expuesta) en tareas de mantenimiento es:", opciones: ["A) Opcional si se cortó la luz", "B) Exigible solo en media tensión", "C) Obligatorio para cualquier trabajador que manipule o intervenga tableros e instalaciones eléctricas", "D) Recomendado pero no normado"], respuestaCorrecta: 2, explicacion: "RIC N°17 exige el uso estricto de EPP dieléctricos homologados para minimizar riesgos de electrocución." },
    { pliego: 18, pregunta: "Al dibujar o presentar un plano eléctrico de planta (la vista superior de la casa), ¿cuáles son las escalas preferidas y estandarizadas por la SEC?", opciones: ["A) 1:10 o 1:20", "B) 1:50 o 1:100", "C) 1:1000 o 1:2000", "D) Sin escala, formato croquis libre"], respuestaCorrecta: 1, explicacion: "RIC N°18: Los planos de disposición de equipos en edificaciones comunes exigen habitualmente escalas de 1:50 o 1:100." },
    { pliego: 18, pregunta: "Para mostrar la estructura interna de los tableros y las protecciones en un proyecto SEC, ¿qué tipo de esquema se debe dibujar obligatoriamente?", opciones: ["A) Diagrama de bloques", "B) Esquema pictórico (3D)", "C) Diagrama Unilineal normalizado", "D) Diagrama de flujos de energía"], respuestaCorrecta: 2, explicacion: "RIC N°18: Todo proyecto eléctrico requiere un Diagrama Unilineal que describa el empalme, alimentador, protecciones (disyuntores/diferenciales) y secciones de cable de cada circuito." },
    { pliego: 19, pregunta: "Antes de energizar por primera vez y de realizar pruebas con instrumentos, la norma obliga a realizar una inspección. ¿Cuál?", opciones: ["A) Inspección térmica con cámara infrarroja", "B) Inspección Visual completa de la instalación", "C) Prueba de humo en las cañerías", "D) Verificación satelital"], respuestaCorrecta: 1, explicacion: "RIC N°19: El primer paso de verificación de toda instalación es la Inspección Visual (para confirmar colores, conexiones firmes, presencia de tapas, etc.) sin tensión." },
    { pliego: 19, pregunta: "Al medir la 'Continuidad' del conductor de tierra de protección, el instrumento utilizado (óhmetro de baja resistencia) debe ser capaz de inyectar una corriente mínima de prueba de:", opciones: ["A) 10 mA", "B) 30 mA", "C) 200 mA", "D) 1 Amperio"], respuestaCorrecta: 2, explicacion: "RIC N°19 exige que la prueba de continuidad de los conductores de protección se realice con un equipo que inyecte al menos 200 mA para garantizar una lectura confiable." },
    { pliego: 19, pregunta: "Durante las pruebas finales, la polaridad de los portalámparas (soquetes) tipo rosca Edison debe verificarse. ¿Dónde debe quedar conectada obligatoriamente la FASE?", opciones: ["A) En el contacto de la rosca exterior metálica", "B) En el contacto central del fondo del portalámpara", "C) En la carcasa del interruptor", "D) Da lo mismo, es corriente alterna"], respuestaCorrecta: 1, explicacion: "RIC N°19: Por seguridad contra contactos directos al cambiar ampolletas, la fase siempre debe ir al punto central profundo, y el neutro a la rosca."}
];